from huggingface_hub import model_info
from dataclasses import dataclass
from typing import Optional

# Approved model licences for production use
APPROVED_MODEL_LICENCES = {
    "apache-2.0",
    "mit",
    "cc-by-4.0",
    "cc-by-sa-4.0",
    "llama2",            # Meta's custom licence — pre-reviewed for internal use
    "mistral",           # Mistral AI Apache 2.0 derivative — pre-reviewed
}

REVIEW_MODEL_LICENCES = {
    "llama3",            # Llama 3 Community Licence — pre-reviewed pending Legal sign-off
    "gemma",             # Google Gemma Terms of Use — pre-reviewed
    "cc-by-nc-4.0",      # Non-commercial only — internal R&D use requires sign-off
}

@dataclass
class ModelLicenceCheck:
    model_id: str
    licence: Optional[str]
    is_approved: bool
    requires_review: bool
    blocked: bool
    message: str

def check_model_licence(model_id: str) -> ModelLicenceCheck:
    info = model_info(model_id)
    lic  = (info.card_data.license or "unknown").lower() if info.card_data else "unknown"

    if lic in APPROVED_MODEL_LICENCES:
        return ModelLicenceCheck(model_id, lic, True, False, False,
                                 f"Approved: {lic}")
    if lic in REVIEW_MODEL_LICENCES:
        return ModelLicenceCheck(model_id, lic, False, True, False,
                                 f"Legal review required for '{lic}' — open governance ticket")
    return ModelLicenceCheck(model_id, lic, False, False, True,
                             f"Unknown or non-commercial licence '{lic}' — blocked until Legal approves")

# Usage during environment provisioning
def validate_models_for_deployment(model_ids: list[str]) -> None:
    failures = []
    for mid in model_ids:
        result = check_model_licence(mid)
        print(result.message)
        if result.blocked:
            failures.append(mid)
    if failures:
        raise RuntimeError(
            f"Deployment blocked: {len(failures)} model(s) have unapproved licences: {failures}"
        )
